// server/src/pdfText.ts
async function pdfToText(buffer) {
  const parser = new PDFParse({ data: new Uint8Array(buffer) });
  try {
    const result = await parser.getText();
    const pages = Array.isArray(result.pages) ? result.pages.length : 0;
    return { text: result.text ?? "", pages };
  } finally {
    await parser.destroy?.();
  }
}

// server/src/pptxGen.ts
var PPTX_MIME = "application/vnd.openxmlformats-officedocument.presentationml.presentation";
var CARBON = {
  dark: "161616",
  blue: "0F62FE",
  grey: "525252",
  light: "F4F4F4",
  white: "FFFFFF"
};
function newDeck() {
  const deck = new PptxGenJS();
  deck.defineLayout({ name: "WIDE", width: 13.33, height: 7.5 });
  deck.layout = "WIDE";
  return deck;
}
function addHeader(deck, slide, title) {
  slide.background = { color: CARBON.white };
  slide.addShape(deck.ShapeType.rect, { x: 0, y: 0, w: 13.33, h: 0.95, fill: { color: CARBON.dark } });
  slide.addShape(deck.ShapeType.rect, { x: 0, y: 0.95, w: 13.33, h: 0.06, fill: { color: CARBON.blue } });
  slide.addText(title, {
    x: 0.45,
    y: 0.12,
    w: 12.4,
    h: 0.7,
    color: CARBON.white,
    bold: true,
    fontSize: 22,
    fontFace: "Arial",
    valign: "middle"
  });
  slide.addText("Made with IBM Bob \xB7 Finance Studio", {
    x: 8.9,
    y: 7.12,
    w: 4.2,
    h: 0.3,
    color: CARBON.grey,
    fontSize: 9,
    fontFace: "Arial",
    align: "right"
  });
}
function addAnnotationPanel(deck, slide) {
  const placeholders = [
    ["Key insight", "Click to add the headline takeaway from this visual."],
    ["Supporting detail", "Click to add the numbers or context behind it."],
    ["Recommended action", "Click to add what leadership should do next."]
  ];
  placeholders.forEach(([heading, hint], i) => {
    const y = 1.35 + i * 1.95;
    slide.addShape(deck.ShapeType.roundRect, {
      x: 9.05,
      y,
      w: 3.85,
      h: 1.75,
      fill: { color: CARBON.light },
      line: { color: "E0E0E0", width: 1 },
      rectRadius: 0.06
    });
    slide.addText(heading, { x: 9.25, y: y + 0.12, w: 3.5, h: 0.35, color: CARBON.blue, bold: true, fontSize: 13, fontFace: "Arial" });
    slide.addText(hint, { x: 9.25, y: y + 0.5, w: 3.5, h: 1.1, color: CARBON.grey, fontSize: 11, fontFace: "Arial" });
  });
}
async function writeDeck(deck, filename, slideCount, warnings) {
  const base64 = await deck.write({ outputType: "base64" });
  return { filename, base64, mimeType: PPTX_MIME, slideCount, warnings };
}
function baseName(originalname) {
  return originalname.replace(/\.[^.]+$/, "");
}
async function imageToPptx(buffer, originalname, mimetype, title) {
  const deck = newDeck();
  const slide = deck.addSlide();
  const slideTitle = title || baseName(originalname);
  addHeader(deck, slide, slideTitle);
  slide.addImage({
    data: `data:${mimetype};base64,${buffer.toString("base64")}`,
    x: 0.45,
    y: 1.35,
    w: 8.35,
    h: 5.6,
    sizing: { type: "contain", w: 8.35, h: 5.6 }
  });
  addAnnotationPanel(deck, slide);
  return writeDeck(deck, `${slideTitle}.pptx`, 1, []);
}
async function pdfToPptx(buffer, originalname, title) {
  const warnings = [];
  const parsed = await pdfToText(buffer);
  const text = (parsed.text ?? "").trim();
  if (!text) throw new Error("PDF appears to be image-only (no extractable text) \u2014 export a page as PNG/JPG and convert that instead.");
  const deck = newDeck();
  const slideTitle = title || baseName(originalname);
  const cover = deck.addSlide();
  addHeader(deck, cover, slideTitle);
  cover.addText(slideTitle, { x: 0.9, y: 2.6, w: 11.5, h: 1.2, color: CARBON.dark, bold: true, fontSize: 40, fontFace: "Arial" });
  cover.addText(`Generated from ${originalname} \xB7 ${parsed.pages || "?"} pages \xB7 fully editable`, {
    x: 0.9,
    y: 3.9,
    w: 11.5,
    h: 0.5,
    color: CARBON.grey,
    fontSize: 16,
    fontFace: "Arial"
  });
  const paragraphs = text.split(/\n{2,}|\f/).map((p) => p.replace(/\s+/g, " ").trim()).filter((p) => p.length > 40);
  const perSlide = 5;
  const maxSlides = 6;
  const groups = [];
  for (let i = 0; i < paragraphs.length && groups.length < maxSlides; i += perSlide) {
    groups.push(paragraphs.slice(i, i + perSlide));
  }
  if (paragraphs.length > maxSlides * perSlide) {
    warnings.push(`Content truncated: ${paragraphs.length} paragraphs, first ${maxSlides * perSlide} included`);
  }
  groups.forEach((group, gi) => {
    const slide = deck.addSlide();
    addHeader(deck, slide, `${slideTitle} \u2014 ${gi + 1} of ${groups.length}`);
    slide.addText(
      group.map((p) => ({
        text: p.length > 300 ? p.slice(0, 300) + "\u2026" : p,
        options: { bullet: { characterCode: "2022" }, fontSize: 13, color: CARBON.dark, fontFace: "Arial", paraSpaceAfter: 10 }
      })),
      { x: 0.7, y: 1.35, w: 12, h: 5.7, valign: "top" }
    );
  });
  return writeDeck(deck, `${slideTitle}.pptx`, 1 + groups.length, warnings);
}
async function buildPptxFromFile(buffer, originalname, mimetype, title) {
  if (mimetype.startsWith("image/")) return imageToPptx(buffer, originalname, mimetype, title);
  if (mimetype === "application/pdf" || /\.pdf$/i.test(originalname)) return pdfToPptx(buffer, originalname, title);
  throw new Error(`Unsupported type for PPTX conversion: ${mimetype || originalname}`);
}

// api/pptx.ts
var config = { api: { bodyParser: false } };
async function readBody(req) {
  const preRead = req.body;
  if (Buffer.isBuffer(preRead) && preRead.length > 0) return preRead;
  if (typeof preRead === "string" && preRead.length > 0) return Buffer.from(preRead, "latin1");
  return new Promise((resolve, reject) => {
    const chunks = [];
    req.on("data", (chunk) => chunks.push(chunk));
    req.on("end", () => resolve(Buffer.concat(chunks)));
    req.on("error", reject);
  });
}
function parseMultipart(buffer, boundary) {
  const boundaryBuf = Buffer.from("--" + boundary);
  const parts = [];
  let start = 0;
  while (start < buffer.length) {
    const idx = buffer.indexOf(boundaryBuf, start);
    if (idx === -1) break;
    const partStart = idx + boundaryBuf.length + 2;
    const nextIdx = buffer.indexOf(boundaryBuf, partStart);
    if (nextIdx === -1) break;
    parts.push(buffer.slice(partStart, nextIdx - 2));
    start = nextIdx;
  }
  let file = null;
  let title = "";
  for (const part of parts) {
    const headerEnd = part.indexOf("\r\n\r\n");
    if (headerEnd === -1) continue;
    const headerStr = part.slice(0, headerEnd).toString();
    const data = part.slice(headerEnd + 4);
    const cdMatch = headerStr.match(/Content-Disposition:[^\r\n]*?[;\s]name="([^"]*)"(?:[^\r\n]*?[;\s]filename="([^"]*)")?/i);
    const ctMatch = headerStr.match(/Content-Type:\s*([^\r\n]+)/i);
    if (!cdMatch) continue;
    const fieldName = cdMatch[1];
    if (fieldName === "file" && cdMatch[2]) {
      file = { filename: cdMatch[2], mimetype: ctMatch?.[1]?.trim() ?? "application/octet-stream", data };
    } else if (fieldName === "title") {
      title = data.toString("utf-8").trim();
    }
  }
  return { file, title };
}
async function handler(req, res) {
  if (req.method !== "POST") {
    res.status(405).json({ error: "Method not allowed" });
    return;
  }
  const contentType = req.headers["content-type"] ?? "";
  const boundaryMatch = contentType.match(/boundary=([^\s;]+)/);
  if (!boundaryMatch) {
    res.status(400).json({ error: "Expected multipart/form-data" });
    return;
  }
  let rawBody;
  try {
    rawBody = await readBody(req);
  } catch {
    res.status(400).json({ error: "Failed to read request body" });
    return;
  }
  const { file, title } = parseMultipart(rawBody, boundaryMatch[1]);
  if (!file) {
    res.status(400).json({ error: "No file found in upload" });
    return;
  }
  try {
    res.json(await buildPptxFromFile(file.data, file.filename, file.mimetype, title || void 0));
  } catch (err) {
    const message = err instanceof Error ? err.message : "PPTX generation failed";
    res.status(message.startsWith("Unsupported") ? 415 : 422).json({ error: message });
  }
}
export {
  config,
  handler as default
};
